class Solution:
    def countSteppingNumbers(self, low: str, high: str) -> int:
        MOD = 10**9 + 7

        def count_less_than(s: str) -> int:
            n = len(s)
            dp = [[[-1 for _ in range(10)] for _ in range(2)] for _ in range(n)]
            visited = set()

            def dfs(pos, tight, leading_zero, prev_digit):
                if pos == n:
                    return 0
                if dp[pos][tight][prev_digit] != -1:
                    return dp[pos][tight][prev_digit]

                limit = int(s[pos]) if tight else 9
                total = 0

                for d in range(0, limit + 1):
                    new_tight = tight and (d == limit)
                    new_leading_zero = leading_zero and (d == 0)
                    new_prev_digit = d

                    if not new_leading_zero:
                        if prev_digit == -1:
                            # Start of number
                            total += 1
                        else:
                            if abs(d - prev_digit) == 1:
                                total += 1
                    else:
                        # Skip leading zeros
                        continue

                    total += dfs(pos + 1, new_tight, new_leading_zero, new_prev_digit)
                    total %= MOD

                dp[pos][tight][prev_digit] = total
                return total

            return dfs(0, True, True, -1)

        def is_stepping(num: int) -> bool:
            s = str(num)
            for i in range(1, len(s)):
                if abs(int(s[i]) - int(s[i - 1])) != 1:
                    return False
            return True

        def generate_stepping_numbers(limit: int) -> set:
            result = set()
            from collections import deque
            queue = deque()
            for d in range(1, 10):
                queue.append(d)
            while queue:
                num = queue.popleft()
                if num > limit:
                    continue
                result.add(num)
                last_digit = num % 10
                next_digits = [last_digit + 1, last_digit - 1]
                for nd in next_digits:
                    if 0 <= nd <= 9:
                        new_num = num * 10 + nd
                        if new_num <= limit:
                            queue.append(new_num)
            return result

        # Convert low and high to integers
        low_int = int(low)
        high_int = int(high)

        # Generate all stepping numbers up to high
        stepping_numbers = generate_stepping_numbers(high_int)

        # Count how many are in [low, high]
        count = 0
        for num in stepping_numbers:
            if low_int <= num <= high_int:
                count += 1
        return count % MOD
